--
-- Table structure for table `ordenes_compra`
--

DROP TABLE IF EXISTS `ordenes_compra`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ordenes_compra` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `seq` bigint unsigned DEFAULT NULL,
  `empresa_tenant_id` bigint unsigned NOT NULL,
  `numero_orden` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `fecha` date DEFAULT NULL,
  `solicitante_id` bigint unsigned NOT NULL,
  `proveedor_id` bigint unsigned DEFAULT NULL,
  `descripcion` text COLLATE utf8mb4_unicode_ci,
  `notas` text COLLATE utf8mb4_unicode_ci,
  `monto` decimal(12,2) NOT NULL DEFAULT '0.00',
  `factura` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estado` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'abierta',
  `recepcion` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'sin recepción',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `created_by` bigint unsigned DEFAULT NULL,
  `updated_by` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `oc_tenant_numero_unique` (`empresa_tenant_id`,`numero_orden`),
  UNIQUE KEY `oc_tenant_seq_unique` (`empresa_tenant_id`,`seq`),
  KEY `ordenes_compra_solicitante_id_foreign` (`solicitante_id`),
  KEY `ordenes_compra_empresa_tenant_id_index` (`empresa_tenant_id`),
  KEY `ordenes_compra_proveedor_id_index` (`proveedor_id`),
