DROP TABLE IF EXISTS `producto_series_historial`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `producto_series_historial` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `empresa_tenant_id` bigint unsigned NOT NULL,
  `producto_serie_id` bigint unsigned NOT NULL,
  `producto_id` bigint unsigned NOT NULL,
  `user_id` bigint unsigned DEFAULT NULL,
  `accion` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `estado_anterior` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `estado_nuevo` varchar(20) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `responsiva_id` bigint unsigned DEFAULT NULL,
  `devolucion_id` bigint unsigned DEFAULT NULL,
  `cambios` json DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `producto_series_historial_producto_serie_id_foreign` (`producto_serie_id`),
  KEY `producto_series_historial_user_id_foreign` (`user_id`),
  KEY `producto_series_historial_empresa_tenant_id_index` (`empresa_tenant_id`),
  KEY `producto_series_historial_producto_id_index` (`producto_id`),
  KEY `producto_series_historial_responsiva_id_index` (`responsiva_id`),
  KEY `producto_series_historial_devolucion_id_index` (`devolucion_id`),
  CONSTRAINT `producto_series_historial_producto_serie_id_foreign` FOREIGN KEY (`producto_serie_id`) REFERENCES `producto_series` (`id`) ON DELETE CASCADE,
  CONSTRAINT `producto_series_historial_user_id_foreign` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=111 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
