--
-- Table structure for table `puestos`
--

DROP TABLE IF EXISTS `puestos`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `puestos` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `empresa_tenant_id` bigint unsigned NOT NULL,
  `folio` bigint unsigned NOT NULL,
  `created_by` bigint unsigned NOT NULL,
  `nombre` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `descripcion` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `ux_puestos_tenant_folio` (`empresa_tenant_id`,`folio`),
  UNIQUE KEY `ux_puestos_tenant_nombre` (`empresa_tenant_id`,`nombre`),
  KEY `puestos_created_by_foreign` (`created_by`),
  KEY `puestos_empresa_tenant_id_nombre_index` (`empresa_tenant_id`,`nombre`),
  KEY `puestos_empresa_tenant_id_index` (`empresa_tenant_id`),
